<style>
    body::selection {
    background-color: #000000;
    color: rgb(7, 89, 18);
    border-radius: 20px;
}
/* شكل المجرى (المكان الذي يتحرك فيه الشريط) */
::-webkit-scrollbar {
    width: 12px;
    /* عرض الشريط */
}

/* لون خلفية المجرى */
::-webkit-scrollbar-track {
    background: #000000;
    border-radius: 10px;
}
::-webkit-scrollbar-track:hover {
    background: #2e8a22;
    border-radius: 10px;
}

/* لون الجزء المتحرك (العمود نفسه) */
::-webkit-scrollbar-thumb {
    background: #2e8a22;
    border-radius: 20px;
    /* يمكنك تغيير اللون هنا ليناسب شعار Behance مثلاً */
    border-radius: 10px;
    border: 2px solid #f1f1f1;
    /* يضيف مسافة صغيرة حول العمود */
}

/* لون العمود عند وضع الماوس عليه */
::-webkit-scrollbar-thumb:hover {
    background: #000000;
}

a{color:inherit;text-decoration:none}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#060608;
  --bg2:#0d0d12;
  --bg3:#13131a;
  --bg4:#1a1a24;
  --border:rgba(255,255,255,0.06);
  --border2:rgba(255,255,255,0.12);
  --text:#eeeae2;
  --muted:#6b6880;
  --muted2:#9896a8;
  --accent:#b8ff57;
  --accent2:#7c5cf6;
  --accent3:#ff5c8a;
  --head:'Clash Display',sans-serif;
  --body:'Cabinet Grotesk',sans-serif;
  --mono:'JetBrains Mono',monospace;
}
html{scroll-behavior:smooth}
body{background:var(--bg);color:var(--text);font-family:var(--body);font-size:16px;line-height:1.7;overflow-x:hidden}

/* GRAIN OVERLAY */
body::before{content:'';position:fixed;inset:0;background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='1'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:0}

/* AMBIENT GLOWS */
.glow-1{position:fixed;width:700px;height:700px;background:radial-gradient(circle,rgba(124,92,246,0.12) 0%,transparent 65%);top:-200px;right:-200px;pointer-events:none;z-index:0;animation:drift1 14s ease-in-out infinite}
.glow-2{position:fixed;width:500px;height:500px;background:radial-gradient(circle,rgba(184,255,87,0.07) 0%,transparent 65%);bottom:-100px;left:-100px;pointer-events:none;z-index:0;animation:drift2 18s ease-in-out infinite}
@keyframes drift1{0%,100%{transform:translate(0,0)}50%{transform:translate(-40px,50px)}}
@keyframes drift2{0%,100%{transform:translate(0,0)}50%{transform:translate(30px,-30px)}}

/* NAV */
nav{position:fixed;top:0;left:0;right:0;z-index:100;display:flex;justify-content:space-between;align-items:center;padding:1.25rem 3rem;border-bottom:1px solid var(--border);backdrop-filter:blur(24px);-webkit-backdrop-filter:blur(24px);background:rgba(6,6,8,0.75)}
.nav-logo{font-family:var(--head);font-weight:700;font-size:1.2rem;color:var(--accent);text-decoration:none;letter-spacing:-0.02em;display:flex;align-items:center;gap:0.5rem}
.nav-logo-dot{width:6px;height:6px;border-radius:50%;background:var(--accent);display:inline-block}
.nav-links{display:flex;gap:2rem;list-style:none}
.nav-links a{font-family:var(--mono);font-size:0.72rem;color:var(--muted);text-decoration:none;letter-spacing:0.08em;text-transform:uppercase;transition:color 0.2s;position:relative}
.nav-links a::after{content:'';position:absolute;bottom:-2px;left:0;width:0;height:1px;background:var(--accent);transition:width 0.2s}
.nav-links a:hover{color:var(--text)}
.nav-links a:hover::after{width:100%}

/* HERO */
#hero{min-height:100vh;display:grid;grid-template-columns:1fr 420px;align-items:center;gap:4rem;padding:9rem 3rem 5rem;position:relative;overflow:hidden;z-index:1}
.hero-eyebrow{font-family:var(--mono);font-size:0.72rem;color:var(--accent);letter-spacing:0.14em;text-transform:uppercase;margin-bottom:1.75rem;display:flex;align-items:center;gap:0.75rem;opacity:0;animation:fadeUp 0.7s 0.2s forwards}
.hero-eyebrow::before{content:'';display:inline-block;width:28px;height:1px;background:var(--accent)}
.hero-name{font-family:var(--head);font-weight:700;font-size:clamp(3.2rem,6.5vw,6rem);line-height:0.92;letter-spacing:-0.04em;margin-bottom:1.75rem;opacity:0;animation:fadeUp 0.7s 0.35s forwards}
.hero-name .outline{-webkit-text-stroke:1px rgba(255,255,255,0.25);color:transparent}
.hero-desc{max-width:500px;font-size:1.05rem;color:var(--muted2);line-height:1.8;margin-bottom:2.5rem;opacity:0;animation:fadeUp 0.7s 0.5s forwards}
.hero-desc strong{color:var(--text);font-weight:600}
.hero-ctas{display:flex;gap:1rem;flex-wrap:wrap;opacity:0;animation:fadeUp 0.7s 0.65s forwards}
.hero-meta{display:flex;gap:2rem;margin-top:3rem;padding-top:2rem;border-top:1px solid var(--border);opacity:0;animation:fadeUp 0.7s 0.8s forwards}
.hero-meta-item{display:flex;flex-direction:column;gap:0.2rem}
.hero-meta-num{font-family:var(--head);font-weight:700;font-size:1.6rem;color:var(--text);letter-spacing:-0.02em}
.hero-meta-label{font-family:var(--mono);font-size:0.68rem;color:var(--muted);letter-spacing:0.1em;text-transform:uppercase}

/* HERO PHOTO SIDE */
.hero-visual{position:relative;z-index:1;opacity:0;animation:fadeUp 0.7s 0.4s forwards}
.hero-card{background:var(--bg3);border:1px solid var(--border2);border-radius:20px;padding:2rem;position:relative;overflow:hidden}
.hero-card::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,rgba(124,92,246,0.08) 0%,transparent 60%);pointer-events:none}
.avatar-ring{width:100px;height:100px;border-radius:50%;background:linear-gradient(135deg,var(--accent2),var(--accent3),var(--accent));padding:2px;margin-bottom:1.25rem}
.avatar-inner{width:100%;height:100%;border-radius:50%;background:var(--bg4);display:flex;align-items:center;justify-content:center;font-family:var(--head);font-size:2rem;font-weight:700;color:var(--accent)}
.hero-card-name{font-family:var(--head);font-weight:700;font-size:1.3rem;margin-bottom:0.25rem;letter-spacing:-0.02em}
.hero-card-role{font-family:var(--mono);font-size:0.72rem;color:var(--accent);letter-spacing:0.08em;margin-bottom:1.5rem}
.hero-card-divider{height:1px;background:var(--border);margin-bottom:1.25rem}
.hero-card-skills{display:flex;flex-wrap:wrap;gap:0.5rem;margin-bottom:1.5rem}
.skill-pill{background:var(--bg4);border:1px solid var(--border);border-radius:100px;padding:0.3rem 0.85rem;font-family:var(--mono);font-size:0.7rem;color:var(--muted2);white-space:nowrap}
.skill-pill.hot{border-color:rgba(184,255,87,0.25);color:var(--accent);background:rgba(184,255,87,0.05)}
.status-dot{width:8px;height:8px;border-radius:50%;background:#22c55e;display:inline-block;margin-right:0.5rem;box-shadow:0 0 0 3px rgba(34,197,94,0.2)}
.hero-card-status{font-family:var(--mono);font-size:0.7rem;color:var(--muted2);display:flex;align-items:center}
.flag-row{display:flex;align-items:center;gap:0.4rem;font-family:var(--mono);font-size:0.7rem;color:var(--muted);margin-top:0.5rem}

/* BUTTONS */
.btn-primary{background:var(--accent);color:#060608;padding:0.85rem 2rem;border-radius:6px;font-family:var(--head);font-weight:700;font-size:0.88rem;letter-spacing:0.01em;text-decoration:none;transition:transform 0.2s,box-shadow 0.2s;display:inline-flex;align-items:center;gap:0.5rem}
.btn-primary:hover{transform:translateY(-2px);box-shadow:0 10px 32px rgba(184,255,87,0.25)}
.btn-ghost{border:1px solid var(--border2);color:var(--text);padding:0.85rem 2rem;border-radius:6px;font-family:var(--head);font-weight:600;font-size:0.88rem;text-decoration:none;transition:border-color 0.2s,background 0.2s;display:inline-flex;align-items:center;gap:0.5rem}
.btn-ghost:hover{border-color:var(--accent);background:rgba(184,255,87,0.04)}

/* MARQUEE */
.marquee-bar{border-top:1px solid var(--border);border-bottom:1px solid var(--border);padding:1.1rem 0;overflow:hidden;background:var(--bg2);position:relative;z-index:1}
.marquee-track{display:flex;gap:3rem;animation:marquee 24s linear infinite;white-space:nowrap;width:max-content}
.marquee-item{font-family:var(--mono);font-size:0.72rem;color:var(--muted);letter-spacing:0.1em;text-transform:uppercase;display:flex;align-items:center;gap:1rem}
.marquee-item::after{content:'✦';color:var(--accent);font-size:0.55rem}
@keyframes marquee{from{transform:translateX(0)}to{transform:translateX(-50%)}}

/* SECTIONS */
section{padding:7rem 3rem;position:relative;z-index:1}
.section-tag{font-family:var(--mono);font-size:0.7rem;color:var(--accent);letter-spacing:0.14em;text-transform:uppercase;margin-bottom:0.75rem;display:flex;align-items:center;gap:0.75rem}
.section-tag::before{content:'';display:inline-block;width:22px;height:1px;background:var(--accent)}
.section-title{font-family:var(--head);font-weight:700;font-size:clamp(2rem,4vw,3rem);letter-spacing:-0.03em;margin-bottom:3.5rem;line-height:1.05}

/* ABOUT */
#about{background:var(--bg2)}
.about-grid{display:grid;grid-template-columns:1.1fr 1fr;gap:5rem;align-items:start;max-width:1100px}
.about-text p{color:var(--muted2);margin-bottom:1.25rem;font-size:1.05rem}
.about-text p strong{color:var(--text);font-weight:600}
.about-tag{display:inline-flex;align-items:center;gap:0.5rem;background:var(--bg3);border:1px solid var(--border);border-radius:100px;padding:0.4rem 1rem;font-family:var(--mono);font-size:0.72rem;color:var(--muted2);margin-bottom:1.75rem}
.about-stats{display:grid;grid-template-columns:1fr 1fr;gap:1rem}
.stat-card{background:var(--bg3);border:1px solid var(--border);border-radius:12px;padding:1.5rem;transition:border-color 0.3s,transform 0.3s}
.stat-card:hover{border-color:rgba(184,255,87,0.3);transform:translateY(-3px)}
.stat-num{font-family:var(--head);font-size:2.6rem;font-weight:700;color:var(--accent);line-height:1;margin-bottom:0.35rem;letter-spacing:-0.03em}
.stat-label{font-family:var(--mono);font-size:0.68rem;color:var(--muted);letter-spacing:0.08em;text-transform:uppercase}

/* SKILLS */
#skills{background:var(--bg)}
.skills-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1.25rem;max-width:1100px}
.skill-cat{background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:1.75rem;transition:border-color 0.3s,transform 0.3s;position:relative;overflow:hidden}
.skill-cat::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,var(--accent2),transparent);opacity:0;transition:opacity 0.3s}
.skill-cat:hover{border-color:var(--border2);transform:translateY(-4px)}
.skill-cat:hover::before{opacity:1}
.skill-cat-icon{font-size:1.4rem;margin-bottom:0.75rem}
.skill-cat-title{font-family:var(--head);font-weight:700;font-size:0.9rem;letter-spacing:0.04em;text-transform:uppercase;color:var(--muted2);margin-bottom:1.25rem}
.skill-tags{display:flex;flex-wrap:wrap;gap:0.4rem}
.skill-tag{background:var(--bg3);border:1px solid var(--border);border-radius:4px;padding:0.3rem 0.7rem;font-family:var(--mono);font-size:0.75rem;color:var(--text);transition:border-color 0.2s,color 0.2s}
.skill-tag:hover,.skill-tag.featured{border-color:rgba(184,255,87,0.3);color:var(--accent);background:rgba(184,255,87,0.04)}

/* EXPERIENCE */
#experience{background:var(--bg2)}
.timeline{max-width:760px;position:relative}
.timeline::before{content:'';position:absolute;left:0;top:8px;bottom:0;width:1px;background:linear-gradient(to bottom,var(--accent),var(--border),transparent)}
.timeline-item{padding-left:2.5rem;padding-bottom:3.5rem;position:relative}
.timeline-item::before{content:'';position:absolute;left:-4px;top:7px;width:9px;height:9px;border-radius:50%;background:var(--accent);box-shadow:0 0 0 3px var(--bg2),0 0 12px rgba(184,255,87,0.4)}
.timeline-date{font-family:var(--mono);font-size:0.7rem;color:var(--accent);letter-spacing:0.1em;margin-bottom:0.5rem}
.timeline-role{font-family:var(--head);font-weight:700;font-size:1.2rem;margin-bottom:0.2rem;letter-spacing:-0.01em}
.timeline-company{font-family:var(--mono);font-size:0.78rem;color:var(--muted2);margin-bottom:1rem;display:flex;align-items:center;gap:0.5rem}
.timeline-desc{color:var(--muted2);font-size:0.97rem;line-height:1.75}
.timeline-tech{display:flex;flex-wrap:wrap;gap:0.4rem;margin-top:0.85rem}
.tech-badge{background:rgba(124,92,246,0.1);border:1px solid rgba(124,92,246,0.2);border-radius:3px;padding:0.2rem 0.6rem;font-family:var(--mono);font-size:0.68rem;color:#b09cf7}

/* PROJECTS */
#projects{background:var(--bg)}
.projects-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(330px,1fr));gap:1.25rem;max-width:1100px}
.project-card{background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:2rem;position:relative;overflow:hidden;transition:border-color 0.3s,transform 0.3s;cursor:pointer}
.project-card::after{content:'';position:absolute;inset:0;background:linear-gradient(135deg,rgba(124,92,246,0.05) 0%,transparent 60%);opacity:0;transition:opacity 0.3s;pointer-events:none}
.project-card:hover{border-color:rgba(124,92,246,0.3);transform:translateY(-5px)}
.project-card:hover::after{opacity:1}
.project-header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:1rem}
.project-num{font-family:var(--mono);font-size:0.68rem;color:var(--muted);letter-spacing:0.1em}
.project-arrow{font-size:1.1rem;color:var(--muted);transition:color 0.2s,transform 0.2s}
.project-card:hover .project-arrow{color:var(--accent);transform:translate(3px,-3px)}
.project-title{font-family:var(--head);font-weight:700;font-size:1.2rem;margin-bottom:0.75rem;transition:color 0.2s;letter-spacing:-0.01em}
.project-card:hover .project-title{color:var(--accent)}
.project-desc{color:var(--muted2);font-size:0.92rem;line-height:1.7;margin-bottom:1.5rem}
.project-stack{display:flex;flex-wrap:wrap;gap:0.4rem}
.stack-tag{background:rgba(124,92,246,0.08);border:1px solid rgba(124,92,246,0.18);border-radius:3px;padding:0.2rem 0.55rem;font-family:var(--mono);font-size:0.68rem;color:#b09cf7}

/* CONTACT */
#contact{background:var(--bg2)}
.contact-inner{max-width:680px;margin:0 auto;text-align:center}
.contact-headline{font-family:var(--head);font-weight:700;font-size:clamp(2.2rem,5vw,3.75rem);line-height:1.02;letter-spacing:-0.03em;margin-bottom:1.25rem}
.contact-headline .highlight{color:var(--accent)}
.contact-sub{color:var(--muted2);font-size:1.05rem;margin-bottom:3rem;max-width:480px;margin-left:auto;margin-right:auto}
.contact-links{display:flex;justify-content:center;gap:1rem;flex-wrap:wrap;margin-bottom:2.5rem}
.contact-link{display:flex;align-items:center;gap:0.6rem;background:var(--bg3);border:1px solid var(--border);border-radius:8px;padding:0.9rem 1.6rem;color:var(--text);text-decoration:none;font-family:var(--mono);font-size:0.8rem;transition:border-color 0.2s,background 0.2s,color 0.2s}
.contact-link:hover{border-color:var(--accent);background:rgba(184,255,87,0.04);color:var(--accent)}
.contact-link svg{width:17px;height:17px;flex-shrink:0}

/* FOOTER */
footer{border-top:1px solid var(--border);padding:2rem 3rem;display:flex;justify-content:space-between;align-items:center;background:var(--bg);position:relative;z-index:1}
.footer-copy{font-family:var(--mono);font-size:0.72rem;color:var(--muted)}
.footer-copy span{color:var(--accent)}
.footer-badge{display:flex;align-items:center;gap:0.5rem;background:var(--bg2);border:1px solid var(--border);border-radius:100px;padding:0.35rem 0.9rem;font-family:var(--mono);font-size:0.68rem;color:var(--muted2)}

/* SCROLL REVEAL */
@keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:translateY(0)}}
.reveal{opacity:0;transform:translateY(32px);transition:opacity 0.65s ease,transform 0.65s ease}
.reveal.visible{opacity:1;transform:translateY(0)}

/* RESPONSIVE */
@media(max-width:960px){
  #hero{grid-template-columns:1fr;padding:7.5rem 1.5rem 4rem;gap:3rem}
  .hero-visual{order:-1}
  .hero-card{max-width:400px;margin:0 auto}
  .about-grid{grid-template-columns:1fr;gap:3rem}
  nav{padding:1rem 1.5rem}
  .nav-links{display:none}
  section{padding:5rem 1.5rem}
  footer{flex-direction:column;gap:0.75rem;text-align:center}
  .hero-meta{gap:1.5rem}
}
</style>
</head>
